// Simulates how codebook size affects consolidation speed
const codebook = [
  { op: 'ATRANS', desc: 'physical transfer', slots: ['agent','object','from','to'] },
  { op: 'PTRANS', desc: 'physical movement', slots: ['agent','object','from','to'] },
  { op: 'MTRANS', desc: 'mental transfer', slots: ['source','content','dest'] },
  { op: 'MBUILD', desc: 'mental construction', slots: ['agent','result'] },
  { op: 'INGEST', desc: 'taking in', slots: ['agent','object'] },
  { op: 'PROPEL', desc: 'force application', slots: ['agent','object','force'] }
];
const memories = [
  { event: 'Teacher explains gravity to students', matchOp: 'MTRANS', congruent: true, rawBits: 4608, compressedBits: 4 },
  { event: 'Chef hands plate to waiter', matchOp: 'ATRANS', congruent: true, rawBits: 3840, compressedBits: 4 },
  { event: 'Quantum entanglement collapse ceremony', matchOp: null, congruent: false, rawBits: 6144, compressedBits: 6144 },
  { event: 'Dog fetches ball from the yard', matchOp: 'PTRANS', congruent: true, rawBits: 3072, compressedBits: 3 },
  { event: 'Hyperdimensional phase transition ritual', matchOp: null, congruent: false, rawBits: 5120, compressedBits: 5120 }
];
const t = Math.floor(Date.now() / 4000) % memories.length;
const m = memories[t];
const ratio = m.rawBits / m.compressedBits;
const replaysNeeded = m.congruent ? Math.ceil(5 / ratio * 10) : 200;
const hours = m.congruent ? 48 : 336;
const bar = (n, max, ch) => ch.repeat(Math.min(Math.round(n/max*30), 30));
let out = '╔══════════════════════════════════════════════════╗\n';
out += '║  SLEEP CONSOLIDATION SIMULATOR                   ║\n';
out += '╚══════════════════════════════════════════════════╝\n\n';
out += `Memory: "${m.event}"\n\n`;
if (m.congruent) {
  out += `✅ SCHEMA MATCH: ${m.matchOp} operator found in codebook\n`;
  out += `   Slots to fill: ${codebook.find(c=>c.op===m.matchOp).slots.join(', ')}\n\n`;
} else {
  out += `❌ NO SCHEMA MATCH: no codebook entry fits\n`;
  out += `   Must encode entire structure from scratch\n\n`;
}
out += `Raw encoding:    ${m.rawBits} bits\n`;
out += `Compressed:      ${m.compressedBits} bits\n`;
out += `Compression:     ${ratio.toFixed(0)}:1\n\n`;
out += `SWR Replays needed: ${bar(replaysNeeded, 200, '█')} ${replaysNeeded}\n`;
out += `Time to consolidate: ${bar(hours, 336, '░')} ${hours}h (${(hours/24).toFixed(0)} days)\n\n`;
out += m.congruent ? '→ Fast track: hippocampus → neocortex in ~48h' : '→ Slow lane: stuck in hippocampus for weeks';
out += '\n\n(cycles every 4s — compare congruent vs incongruent memories)';
return out;

// Simulate Archivist-Skeptic debate rounds
const memories = [
  { event: 'Colleague shared project update (MTRANS)', novelty: 0.2, emotional: 0.1, compression: 0.95, redundancy: 0.8 },
  { event: 'Learned new cooking technique (MBUILD)', novelty: 0.8, emotional: 0.5, compression: 0.7, redundancy: 0.1 },
  { event: 'Walked to the store (PTRANS)', novelty: 0.05, emotional: 0.02, compression: 0.99, redundancy: 0.95 },
  { event: 'Witnessed car accident (PROPEL+CAUSE)', novelty: 0.9, emotional: 0.95, compression: 0.3, redundancy: 0.05 },
  { event: 'Read about alien math notation (???)', novelty: 0.99, emotional: 0.6, compression: 0.05, redundancy: 0.01 },
  { event: 'Had coffee at usual café (INGEST)', novelty: 0.1, emotional: 0.3, compression: 0.98, redundancy: 0.9 }
];
const round = Math.floor(Date.now() / 5000) % memories.length;
const m = memories[round];
const archScore = (m.novelty * 0.3 + m.emotional * 0.3 + (1-m.redundancy) * 0.4).toFixed(2);
const skeptScore = (m.redundancy * 0.4 + (1-m.novelty) * 0.3 + (1-m.emotional) * 0.3).toFixed(2);
const winner = archScore > skeptScore ? 'ARCHIVIST' : 'SKEPTIC';
const decision = archScore > skeptScore 
  ? (m.compression > 0.8 ? '⚡ FAST CONSOLIDATE (schema match!)' : m.compression < 0.2 ? '🔧 FLAG FOR CODEBOOK EXPANSION' : '💾 KEEP IN HIPPOCAMPAL BUFFER')
  : '🗑️ FORGET (not worth the storage)';
let out = '╔══════════════════════════════════════════════════╗\n';
out += '║  🌙 ARCHIVIST vs SKEPTIC — Sleep Debate          ║\n';
out += '╚══════════════════════════════════════════════════╝\n\n';
out += `Memory under review:\n  "${m.event}"\n\n`;
out += '┌─── ARCHIVIST argues to KEEP ───────────────────┐\n';
out += `│ Novelty:      ${('█'.repeat(Math.round(m.novelty*10))).padEnd(10)} ${(m.novelty*100).toFixed(0)}%      │\n`;
out += `│ Emotional:    ${('█'.repeat(Math.round(m.emotional*10))).padEnd(10)} ${(m.emotional*100).toFixed(0)}%      │\n`;
out += `│ Uniqueness:   ${('█'.repeat(Math.round((1-m.redundancy)*10))).padEnd(10)} ${((1-m.redundancy)*100).toFixed(0)}%      │\n`;
out += `│ TOTAL SCORE:  ${archScore}                           │\n`;
out += '└────────────────────────────────────────────────┘\n\n';
out += '┌─── SKEPTIC argues to FORGET ──────────────────┐\n';
out += `│ Redundancy:   ${('█'.repeat(Math.round(m.redundancy*10))).padEnd(10)} ${(m.redundancy*100).toFixed(0)}%      │\n`;
out += `│ Mundaneness:  ${('█'.repeat(Math.round((1-m.novelty)*10))).padEnd(10)} ${((1-m.novelty)*100).toFixed(0)}%      │\n`;
out += `│ Low emotion:  ${('█'.repeat(Math.round((1-m.emotional)*10))).padEnd(10)} ${((1-m.emotional)*100).toFixed(0)}%      │\n`;
out += `│ TOTAL SCORE:  ${skeptScore}                           │\n`;
out += '└────────────────────────────────────────────────┘\n\n';
out += `Winner: ${winner}  →  Decision: ${decision}\n`;
out += `Compression ratio: ${(1/(1-m.compression+0.01)).toFixed(0)}:1\n\n`;
out += '(cycles every 5s — watch different memories get debated)';
return out;
